package operators;

public class Relational {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		System.out.println(10 < 20);
		System.out.println(10 > 5);
		System.out.println(10 <= 20);
		System.out.println(10 <= 10);
		System.out.println(10 >= 5);
		System.out.println(10 == 6);
		System.out.println(10 != 10);
	}

}
